func testPoliticalBeliefToManyRemoveOpUserProfiles(t *testing.T) {
	var err error

	ctx := context.Background()
	tx := MustTx(boil.BeginTx(ctx, nil))
	defer func() { _ = tx.Rollback() }()

	var a PoliticalBelief
	var b, c, d, e UserProfile

	seed := randomize.NewSeed()
	if err = randomize.Struct(seed, &a, politicalBeliefDBTypes, false, strmangle.SetComplement(politicalBeliefPrimaryKeyColumns, politicalBeliefColumnsWithoutDefault)...); err != nil {
		t.Fatal(err)
	}
	foreigners := []*UserProfile{&b, &c, &d, &e}
	for _, x := range foreigners {
		if err = randomize.Struct(seed, x, userProfileDBTypes, false, strmangle.SetComplement(userProfilePrimaryKeyColumns, userProfileColumnsWithoutDefault)...); err != nil {
			t.Fatal(err)
		}
	}

	if err := a.Insert(ctx, tx, boil.Infer()); err != nil {
		t.Fatal(err)
	}

	err = a.AddUserProfiles(ctx, tx, true, foreigners...)
	if err != nil {
		t.Fatal(err)
	}

	count, err := a.UserProfiles().Count(ctx, tx)
	if err != nil {
		t.Fatal(err)
	}
	if count != 4 {
		t.Error("count was wrong:", count)
	}

	err = a.RemoveUserProfiles(ctx, tx, foreigners[:2]...)
	if err != nil {
		t.Fatal(err)
	}

	count, err = a.UserProfiles().Count(ctx, tx)
	if err != nil {
		t.Fatal(err)
	}
	if count != 2 {
		t.Error("count was wrong:", count)
	}

	if !queries.IsValuerNil(b.PoliticalBeliefID) {
		t.Error("want b's foreign key value to be nil")
	}
	if !queries.IsValuerNil(c.PoliticalBeliefID) {
		t.Error("want c's foreign key value to be nil")
	}

	if b.R.PoliticalBelief != nil {
		t.Error("relationship was not removed properly from the foreign struct")
	}
	if c.R.PoliticalBelief != nil {
		t.Error("relationship was not removed properly from the foreign struct")
	}
	if d.R.PoliticalBelief != &a {
		t.Error("relationship to a should have been preserved")
	}
	if e.R.PoliticalBelief != &a {
		t.Error("relationship to a should have been preserved")
	}

	if len(a.R.UserProfiles) != 2 {
		t.Error("should have preserved two relationships")
	}

	// Removal doesn't do a stable deletion for performance so we have to flip the order
	if a.R.UserProfiles[1] != &d {
		t.Error("relationship to d should have been preserved")
	}
	if a.R.UserProfiles[0] != &e {
		t.Error("relationship to e should have been preserved")
	}
}

